// components/dashboard/QuickActions.tsx
'use client';

import { Plus, FileText, Users, Calendar, Download, Settings } from 'lucide-react';

const quickActions = [
  { icon: Plus, label: 'New Project', description: 'Create a new project', color: 'bg-blue-500' },
  { icon: FileText, label: 'Generate Report', description: 'Create project report', color: 'bg-green-500' },
  { icon: Users, label: 'Add Team Member', description: 'Invite new member', color: 'bg-purple-500' },
  { icon: Calendar, label: 'Schedule Meeting', description: 'Plan project review', color: 'bg-orange-500' },
  { icon: Download, label: 'Export Data', description: 'Download project data', color: 'bg-indigo-500' },
  { icon: Settings, label: 'Settings', description: 'Configure system', color: 'bg-gray-500' },
];

export default function QuickActions() {
  return (
    <div className="bg-white rounded-xl border shadow-sm p-6">
      <h2 className="text-lg font-semibold mb-6">Quick Actions</h2>
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
        {quickActions.map((action, index) => {
          const Icon = action.icon;
          return (
            <button
              key={index}
              className="flex flex-col items-center p-4 border rounded-lg hover:bg-gray-50 transition-colors group"
            >
              <div className={`w-12 h-12 rounded-lg ${action.color} flex items-center justify-center mb-3 group-hover:scale-110 transition-transform`}>
                <Icon className="w-6 h-6 text-white" />
              </div>
              <span className="font-medium text-sm">{action.label}</span>
              <span className="text-xs text-gray-500 mt-1">{action.description}</span>
            </button>
          );
        })}
      </div>
    </div>
  );
}